import Fastify from 'fastify';

const fastify = Fastify();

// Global: runs on every route
fastify.addHook('onRequest', async (req, reply) => {
  req.log.info({ url: req.url }, 'incoming request');
});

// Scoped: only routes inside this register block
fastify.register(async (instance) => {
  instance.addHook('preHandler', async (req, reply) => {
    if (!req.headers.authorization) {
      return reply.code(401).send({ error: 'Unauthorized' });
    }
  });

  instance.get('/secure', async () => ({ data: 'protected' }));
});

// This route skips the preHandler above — different scope
fastify.get('/public', async () => ({ data: 'open' }));

await fastify.listen({ port: 3000 });

