import Fastify from 'fastify';
import sensible from '@fastify/sensible';

const app = Fastify({ logger: true });
await app.register(sensible);

app.setErrorHandler((error, request, reply) => {
  reply.log.error(error);

  const statusCode = error.statusCode ?? 500;
  const isValidation = Array.isArray(error.validation);

  reply.status(statusCode).send({
    success: false,
    code: isValidation ? 'VALIDATION_ERROR' : (error.code ?? 'INTERNAL_ERROR'),
    message: statusCode < 500 ? error.message : 'An unexpected error occurred',
    details: isValidation ? error.validation : undefined,
  });
});

app.get('/user/:id', async (request) => {
  const { id } = request.params as { id: string };
  if (!id.match(/^\d+$/)) throw app.httpErrors.badRequest('id must be numeric');
  return { id };
});

import Fastify from 'fastify';
import jwt from '@fastify/jwt';

const app = Fastify();
await app.register(jwt, { secret: process.env.JWT_SECRET! });

app.decorate('authenticate', async (request, reply) => {
  await request.jwtVerify(); // throws 401 if invalid/expired
});

app.register(async (scope) => {
  scope.addHook('preHandler', app.authenticate);

  scope.get('/me', async (request) => {
    return { user: request.user }; // decoded JWT payload
  });

  scope.get('/admin', {
    preHandler: [app.authenticate, async (req, reply) => {
      if (req.user.role !== 'admin') reply.code(403).send({ error: 'Forbidden' });
    }],
  }, async (request) => ({ ok: true }));
}, { prefix: '/api' });

import Fastify from 'fastify';

const app = Fastify();

app.setErrorHandler((err, req, reply) => {
  if (err.validation) {
    return reply.status(400).send({ error: 'Validation failed', details: err.validation });
  }
  reply.status(500).send({ error: 'Internal server error' });
});

